import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Paths;

public class SafePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";

        String baseDirectory = "/var/www/html/data/";
        String normalizedPath = Paths.get(baseDirectory).resolve(userInput).normalize().toString();

        if (!normalizedPath.startsWith(baseDirectory)) {
            System.err.println("Invalid path specified.");
            return;
        }

        try {
            File file = new File(normalizedPath);
            InputStream inputStream = new FileInputStream(file);

            int data = inputStream.read();
            while (data != -1) {
                System.out.print((char) data);
                data = inputStream.read();
            }

            inputStream.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

